      }
    } catch (error) {
      this.showAlert('errorMotion', `Error: ${error.message}`, 'error');
    } finally {
      this.isProcessing = false;
      this.showLoader('loaderMotion', false);
    }
  }

  // ==================== VIDEO EDIT SUITE ====================
  setupVideoEdit() {
    this.setupUploadZone('uploadZoneVideoEdit', 'fileInputVideoEdit', 'videoEdit', 'fileNameVideoEdit');

